// src/utils/shippingService.js

export const calcularEnvio = (distanciaKm) => {
  const COSTO_BASE = 800;
  const COSTO_POR_KM = 250;
  
  if (!distanciaKm || distanciaKm <= 0) return 0;
  
  return COSTO_BASE + (distanciaKm * COSTO_POR_KM);
};

export const ESTADOS_ENVIO = {
  PENDIENTE: { label: 'Preparando pedido', color: '#f39c12' },
  EN_CAMINO: { label: 'En camino', color: '#3498db' },
  ENTREGADO: { label: 'Entregado', color: '#27ae60' }
};
